import Foundation

enum TodoStatus: String, Codable {
    case pending
    case inProgress
    case done
}

struct TodoItem: Codable, Identifiable {
    var id: UUID = UUID()
    var title: String
    var status: TodoStatus = .pending
    var createdAt: Date = Date()
    var dueAt: Date? = nil

    var isOverdue: Bool {
        guard let dueAt else { return false }
        return dueAt < Date() && status != .done
    }

    func mark(as newStatus: TodoStatus) -> TodoItem {
        var copy = self
        copy.status = newStatus
        return copy
    }
}
